```python
def on_done(task: asyncio.Task):
    try:
        result = task.result()  # returns value or re-raises exception/cancellation
        print("success:", result)
    except asyncio.CancelledError:
        print("cancelled")
    except Exception as e:
        print("failed:", repr(e))
```

